import java.util.*;

public class Main {
    public static void main(String[] args) {
        List<String> names = new ArrayList<>(Arrays.asList("Charlie", "Alice", "Bob", "David"));

        // Lambda as Comparator:
        names.sort((a, b) -> a.compareTo(b));
        System.out.println(names);

        // Lambda in forEach:
        names.forEach(name -> System.out.println("Hello, " + name));

        // Lambda as Predicate:
        names.removeIf(name -> name.startsWith("D"));
        System.out.println(names);
    }
}

import java.util.*;
import java.util.stream.*;

public class Main {
    static String addExclamation(String s) { return s + "!"; }

    public static void main(String[] args) {
        List<String> words = Arrays.asList("hello", "world", "java");

        // Method reference instead of lambda:
        words.forEach(System.out::println);   // ClassName::staticMethod from instance

        // Static method reference:
        List<String> excited = words.stream()
            .map(Main::addExclamation)   // static method reference
            .collect(Collectors.toList());
        System.out.println(excited);

        // Instance method reference:
        List<String> upper = words.stream()
            .map(String::toUpperCase)    // instance method of String
            .collect(Collectors.toList());
        System.out.println(upper);
    }
}

import java.util.*;
import java.util.stream.*;

public class Main {
    public static void main(String[] args) {
        List<String> names = Arrays.asList("Alice", "Bob", "Carol", "David", "Eve", "Frank");

        // Names longer than 4 chars, uppercased:
        List<String> result = names.stream()
            .filter(n -> n.length() > 4)
            .map(String::toUpperCase)
            .collect(Collectors.toList());
        System.out.println(result);

        // Count names starting with vowels:
        long count = names.stream()
            .filter(n -> "AEIOU".indexOf(n.charAt(0)) >= 0)
            .count();
        System.out.println("Vowel names: " + count);
    }
}

import java.util.*;
import java.util.stream.*;

public class Main {
    public static void main(String[] args) {
        List<Integer> numbers = Arrays.asList(5, 3, 8, 1, 5, 9, 3, 7, 2, 8);

        // Sum using reduce:
        int sum = numbers.stream()
            .reduce(0, Integer::sum);
        System.out.println("Sum: " + sum);

        // Sorted and distinct:
        List<Integer> sorted = numbers.stream()
            .distinct()
            .sorted()
            .collect(Collectors.toList());
        System.out.println(sorted);

        // Statistics using IntStream:
        IntSummaryStatistics stats = numbers.stream()
            .mapToInt(Integer::intValue)
            .summaryStatistics();
        System.out.println("Max: " + stats.getMax());
        System.out.println("Avg: " + stats.getAverage());
    }
}

import java.util.*;
import java.util.stream.*;

public class Main {
    public static void main(String[] args) {
        List<String> words = Arrays.asList("apple", "ant", "banana", "avocado", "berry", "apricot");

        // Join to comma-separated string:
        String joined = words.stream()
            .filter(w -> w.startsWith("a"))
            .collect(Collectors.joining(", "));
        System.out.println(joined);

        // Group by first letter:
        Map<Character, List<String>> grouped = words.stream()
            .collect(Collectors.groupingBy(w -> w.charAt(0)));
        grouped.forEach((k, v) -> System.out.println(k + ": " + v));

        // Count per letter:
        Map<Character, Long> counts = words.stream()
            .collect(Collectors.groupingBy(w -> w.charAt(0), Collectors.counting()));
        System.out.println("Counts: " + counts);
    }
}

