import java.util.*;
import java.util.stream.*;

public class Main {
    public static void main(String[] args) {
        List<String> names = Arrays.asList("Alice", "Bob", "Carol");

        // findFirst returns Optional — might be empty:
        Optional<String> firstB = names.stream()
            .filter(n -> n.startsWith("B"))
            .findFirst();

        firstB.ifPresent(n -> System.out.println("Found: " + n));

        Optional<String> firstZ = names.stream()
            .filter(n -> n.startsWith("Z"))
            .findFirst();

        System.out.println(firstZ.orElse("None found"));
        System.out.println(firstZ.isPresent());

        // Transform if present:
        String result = firstB
            .map(String::toUpperCase)
            .orElse("NO RESULT");
        System.out.println(result);
    }
}
